sql:
SELECT i.individual_id, i.age, es.status_name, es.description
FROM individuals i
INNER JOIN employment_statuses es ON i.employment_status_id = es.employment_status_id;

SELECT individual_id 
FROM individuals 
LIMIT 10;

external_knowledge:
- "financially successful" refers to individuals with positive capital gains;
- "couples" refers to individuals who are married;
- "popular" in this context means the number of individuals in each job.

sql:
SELECT COUNT(*)
FROM individuals
WHERE age = (SELECT age FROM individuals WHERE social_security_number = '123-45-6789');

SELECT age
FROM individuals
WHERE income = (SELECT MAX(income) FROM individuals);
